(window.webpackJsonp=window.webpackJsonp||[]).push([[379],{1006:function(n,e){n.exports="\x3c!-- \ntitle: 21-Taro调用API\nsort: \n--\x3e \n\n## 基础\n\n### 跳转\n\n```react\n// 直接跳转\nTaro.redirectTo({\n  url: '/pages/reserve/index'\n})\n\n// 当前界面跳转\nTaro.navigateTo({\n  url: '/pages/calendar/index'\n})\n// 向前一个页面写入数据\nTaro.getCurrentPages()[0].setData({\n  data: this.state.,\n})\n// 跳回前一个页面\nTaro.navigateBack({\n  delta: 1\n})\n```\n\n### 存储\n\n```react\n// 存储\nTaro.setStorage({\n  key: \"userInfo\",\n  data: res.userInfo\n})\n// 读取\nTaro.getStorage({\n  key: 'openId'\n})\n```\n\n\n\n## 云开发\n\n### 开发云函数\n\n```js\nconst cloud = require('wx-server-sdk')\n// 初始化\ncloud.init({\n  env: cloud.DYNAMIC_CURRENT_ENV\n})\n\nexports.main = async (event, context) => {\n\n  const { OPENID } = cloud.getWXContext()\n  \n  return {\n    code: 200,\n    msg: '获取成功',\n    openId: OPENID,\n  }\n\n}\n```\n\n### 调用云函数\n\n```react\nTaro.cloud\n  .callFunction({\n    name: \"login\",\n    data: {}\n  })\n  .then(res => {\n    Taro.setStorage({\n      key: \"openId\",\n      data: res.result.openId\n    }).then(() => {\n      this.getDBUser(res.result.openId)\n    })\n  })\n```\n\n### 数据库\n\n```react\n// 小程序端调用数据库\nconst userDB = Taro.cloud.database().collection('user\nawait userDB.where({\n  _openid: openId\n}).get({\n  success: (res) => {\n    // 用户不存在则创建\n    if (res.data.length == 0) {\n      userDB.add({\n        data: {\n          point: 0,\n          nickName: this.state.nickName,\n        },\n      })\n      // 用户存在则获取积分\n    } else {\n      this.setState({ point: res.data[0].point })\n    }\n  },\n})\n\n// 服务端调用数据库\nconst cloud = require('wx-server-sdk')\n// 初始化\ncloud.init({\n\tenv: cloud.DYNAMIC_CURRENT_ENV\n})\nconst userDB = cloud.database().collection('users')\nexports.main = async (event, context) => {\n  const usersInfo =  await userDB.where({\n    date: date,\n  }).get()\n}\n```\n\n"}}]);